import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../../../services/auth.service';

@Component({
  selector: 'app-login',
  templateUrl: './login.component.html'
})
export class LoginComponent {
  // FormGroup representa todo el formulario en TypeScript. Nos permite leer valores y ver si hay errores.
  loginForm: FormGroup;
  // Mensaje de error para mostrar si el usuario se equivoca.
  errorMessage: string = '';

  constructor(
    private fb: FormBuilder, // FormBuilder es una utilidad para crear el FormGroup fácilmente
    private authService: AuthService,
    private router: Router
  ) {
    // Definimos los campos del formulario y sus validaciones obligatorias (Required) y de formato de Email.
    this.loginForm = this.fb.group({
      email: ['', [Validators.required, Validators.email]],
      password: ['', Validators.required]
    });
  }

  // Método que se ejecuta cuando el usuario presiona "Iniciar Sesión"
  onSubmit() {
    // Si el formulario es inválido (ej. campos vacíos), no hacemos nada.
    if (this.loginForm.invalid) return;

    // Llamamos a nuestro servicio de autenticación
    this.authService.login(this.loginForm.value).subscribe({
      next: () => {
        // Si todo sale bien, lo mandamos a la pantalla de canchas.
        this.router.navigate(['/canchas']);
      },
      error: (err) => {
        // Si el backend nos responde con un error (ej. credenciales inválidas), lo mostramos en pantalla.
        this.errorMessage = err.error?.mensaje || 'Error al iniciar sesión';
      }
    });
  }
}
<div class="container mt-5">
  <div class="row justify-content-center">
    <div class="col-md-6">
      <div class="card shadow-sm">
        <div class="card-body">
          <h2 class="card-title text-center mb-4">Iniciar Sesión</h2>

          <!-- Alerta roja si hay un error al hacer login -->
          <div *ngIf="errorMessage" class="alert alert-danger">
            {{ errorMessage }}
          </div>

          <!-- Enlazamos este formulario HTML con nuestro 'loginForm' en TypeScript. 
               (ngSubmit) ejecuta la función onSubmit() de TypeScript -->
          <form [formGroup]="loginForm" (ngSubmit)="onSubmit()">

            <div class="mb-3">
              <label class="form-label">Correo Electrónico</label>
              <!-- formControlName le dice a Angular a qué campo de TypeScript corresponde este input -->
              <input type="email" class="form-control" formControlName="email" placeholder="tu@email.com">

              <!-- Mostramos un error si el usuario tocó el campo y lo dejó vacío o con formato inválido -->
              <div *ngIf="loginForm.get('email')?.invalid && loginForm.get('email')?.touched" class="text-danger small mt-1">
                Ingresa un correo válido.
              </div>
            </div>

            <div class="mb-3">
              <label class="form-label">Contraseña</label>
              <input type="password" class="form-control" formControlName="password" placeholder="Tu contraseña">
              <div *ngIf="loginForm.get('password')?.invalid && loginForm.get('password')?.touched" class="text-danger small mt-1">
                La contraseña es obligatoria.
              </div>
            </div>

            <!-- El botón se deshabilita automáticamente si el formulario es inválido -->
            <div class="d-grid gap-2">
              <button type="submit" class="btn btn-primary" [disabled]="loginForm.invalid">Entrar</button>
            </div>

            <div class="text-center mt-3">
              ¿No tienes cuenta? <a routerLink="/register">Regístrate aquí</a>
            </div>

          </form>
        </div>
      </div>
    </div>
  </div>
</div>
